:root {
  --card-bg: #ffffff;
  --card-border: #e2e8f0;
  --card-radius: 16px;

  --avatar-bg: #6c47ff;
  --avatar-text: #ffffff;
  --status-online: #22c55e;

  --name-color: #0f172a;
  --role-color: #6c47ff;
  --dept-color: #94a3b8;

  --btn-message-bg: #6c47ff;
  --btn-message-text: #ffffff;
  --btn-follow-bg: #f1f5f9;
  --btn-follow-text: #0f172a;
  --btn-radius: 8px;

  --stat-value-color: #0f172a;
  --stat-label-color: #94a3b8;
  --stat-divider: #e2e8f0;

  --skills-title-color: #64748b;
  --skill-primary-bg: #ede9fe;
  --skill-primary-text: #6c47ff;
  --skill-secondary-bg: #f1f5f9;
  --skill-secondary-text: #475569;
  --skill-accent-bg: #fef3c7;
  --skill-accent-text: #d97706;
  --skill-radius: 6px;

  --avail-label-color: #64748b;
  --avail-track-bg: #e2e8f0;
  --avail-fill-bg: #6c47ff;
  --avail-percent-color: #0f172a;
}

.profile-card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: var(--card-radius);
  padding: 20px;
  width: 480px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.profile-header {
  display: flex;
  align-items: center;
  gap: 14px;
}

.avatar {
  position: relative;
  width: 56px;
  height: 56px;
  flex-shrink: 0;
}

.avatar-initials {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 56px;
  height: 56px;
  border-radius: 50%;
  background: var(--avatar-bg);
  color: var(--avatar-text);
  font-size: 18px;
  font-weight: 700;
}

.status-dot {
  position: absolute;
  bottom: 2px;
  right: 2px;
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: var(--status-online);
  border: 2px solid var(--card-bg);
}

.profile-info {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.profile-name {
  font-size: 18px;
  font-weight: 700;
  color: var(--name-color);
  margin: 0;
  line-height: 1.2;
}

.profile-role {
  font-size: 13px;
  font-weight: 600;
  color: var(--role-color);
}

.profile-dept {
  font-size: 12px;
  color: var(--dept-color);
}

.profile-actions {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.btn-message,
.btn-follow {
  padding: 6px 14px;
  border: none;
  border-radius: var(--btn-radius);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
}

.btn-message {
  background: var(--btn-message-bg);
  color: var(--btn-message-text);
}

.btn-follow {
  background: var(--btn-follow-bg);
  color: var(--btn-follow-text);
}

.stats-row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  border: 1px solid var(--stat-divider);
  border-radius: 10px;
  overflow: hidden;
}

.stat-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 10px 8px;
  gap: 2px;
  border-right: 1px solid var(--stat-divider);
}

.stat-item:last-child {
  border-right: none;
}

.stat-value {
  font-size: 17px;
  font-weight: 700;
  color: var(--stat-value-color);
  line-height: 1.2;
}

.stat-label {
  font-size: 11px;
  color: var(--stat-label-color);
  font-weight: 500;
}

.skills-section {
  display: flex;
  align-items: center;
  gap: 10px;
}

.skills-title {
  font-size: 12px;
  font-weight: 600;
  color: var(--skills-title-color);
  white-space: nowrap;
}

.skills-list {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.skill-tag {
  padding: 3px 10px;
  border-radius: var(--skill-radius);
  font-size: 12px;
  font-weight: 600;
}

.skill-primary {
  background: var(--skill-primary-bg);
  color: var(--skill-primary-text);
}

.skill-secondary {
  background: var(--skill-secondary-bg);
  color: var(--skill-secondary-text);
}

.skill-accent {
  background: var(--skill-accent-bg);
  color: var(--skill-accent-text);
}

.availability-bar {
  display: flex;
  align-items: center;
  gap: 10px;
}

.avail-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--avail-label-color);
  white-space: nowrap;
}

.avail-track {
  flex: 1;
  height: 8px;
  border-radius: 99px;
  background: var(--avail-track-bg);
  overflow: hidden;
}

.avail-fill {
  width: 72%;
  height: 100%;
  border-radius: 99px;
  background: var(--avail-fill-bg);
}

.avail-percent {
  font-size: 13px;
  font-weight: 700;
  color: var(--avail-percent-color);
  white-space: nowrap;
}
